# Build the ALL_CITIES list
ALL_CITIES = cities


def get_city(slug: str):
    """Look up a city dict by its URL slug."""
    for city in ALL_CITIES:
        if city["slug"] == slug:
            return city
    return None


def get_cities_by_county(county_slug: str):
    """Return all city dicts for a given county slug."""
    return [c for c in ALL_CITIES if c["county_slug"] == county_slug]


